#include<bits/stdc++.h>
using namespace std;
int a[1501],dp[1501][1501];
int main()
{
	int n,s;
	scanf("%d%d",&n,&s);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	sort(a+1,a+1+n);
	int d=(s-1)/(n-1);
	memset(dp,0x3f,sizeof(dp));
	dp[1][0]=a[1]-1;
	for(int i=2;i<=n;i++)
	{
		for(int j=0;j<=min(i-1,(s-1)-(n-1)*d);j++)
		{
			if(j==0)
			{
				dp[i][j]=dp[i-1][j]+abs(j+d*(i-1)+1-a[i]);
			}
			else
			{
				dp[i][j]=min(dp[i-1][j-1],dp[i-1][j])+abs(j+d*(i-1)+1-a[i]);
			}
		}
	}
	printf("%d",dp[n][(s-1)-(n-1)*d]);
	return 0;
}
